def count_occurrences(lst, x):
    if len(lst) == 0:
        return 0
    count = 0
    if lst[0] == x:
        count = 1
    return count + count_occurrences(lst[1:], x)

input_line = input().split()
numbers = []
for num in input_line:
    numbers.append(int(num))
x = int(input())

result = count_occurrences(numbers, x)
print(result)
